mapper.update:
UPDATE TB_BOARD
SET VIEW_COUNT = VIEW_COUNT + 1
WHERE BOARD_ID = #{boardId}

mapper.insert:
	INSERT INTO TB_BOARD
	(
    	BOARD_ID
    	, TITLE
    	, CONTENT
    	, WRITER_ID
    	, IS_SECRET
	)
	VALUES
	(
    	#{boardId}
    	, #{title}
    	, #{content}
    	, #{writerId}
    	, #{isSecret}
	)

	INSERT INTO TB_BOARD_FILE
	(
    	FILE_ID
    	, BOARD_ID
    	, ORIGIN_NAME
    	, SAVE_NAME
    	, SAVE_PATH
    	, FILE_SIZE
    	, FILE_EXT
	)
	VALUES
	(
    	SEQ_TB_BOARD_FILE.NEXTVAL,
    	#{boardId}
    	, #{originName}
    	, #{saveName}
    	, #{savePath}
    	, #{fileSize}
    	, #{fileExt}
	)

mapper.update:
	UPDATE TB_BOARD
	SET
    	TITLE = #{title}
    	, CONTENT = #{content}
    	, IS_SECRET = #{isSecret}
    	, UPD_DATE = SYSDATE
	WHERE BOARD_ID = #{boardId}
  	AND WRITER_ID = #{writerId}

mapper.delete:
DELETE FROM TB_BOARD
WHERE BOARD_ID = #{boardId}
  AND WRITER_ID = #{writerId}
